export interface User {
  id: string;
  name: string;
  phone: string;
  balance: number;
}

export type AppView = 'home' | 'recharge' | 'add-balance' | 'bill-pay' | 'transfer' | 'history' | 'profile' | 'login' | 'signup';

export interface Transaction {
  id: string;
  type: 'Recharge' | 'Bill Pay' | 'Transfer' | 'Add Balance';
  amount: number;
  date: string;
  status: 'Success' | 'Pending' | 'Failed';
  description: string;
}

export enum PaymentMethod {
  NAGAD = 'Nagad',
  ROCKET = 'Rocket',
  CELLFIN = 'Cellfin'
}

export const APP_NAME = "Mahid Telecom";
export const HELPLINE_WHATSAPP = "01920544401";
export const WHATSAPP_LINK = `https://wa.me/8801920544401`;
export const APK_DOWNLOAD_URL = "https://example.com/mahid-telecom.apk";

export const PAYMENT_NUMBERS = {
  NAGAD: "01920544401",
