import React, { useState, useEffect } from 'react';
import { Home, User, Smartphone, History, PlusCircle, CreditCard, Send, LogOut, MessageSquare, Share2, Download, ShieldCheck } from 'lucide-react';
import { AppView, User as UserType, Transaction } from './types';
import { APP_NAME, WHATSAPP_LINK, APK_DOWNLOAD_URL } from './constants';
import Login from './views/Login';
import SignUp from './views/SignUp';
import HomeView from './views/Home';
import MobileRecharge from './views/MobileRecharge';
import AddBalance from './views/AddBalance';
import BillPay from './views/BillPay';
import BalanceTransfer from './views/BalanceTransfer';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>('login');
  const [user, setUser] = useState<UserType | null>(null);
  const [history, setHistory] = useState<Transaction[]>([]);

  // Mock initial data
  useEffect(() => {
    const mockHistory: Transaction[] = [
      { id: '1', type: 'Recharge', amount: 50, date: '2023-10-25 14:30', status: 'Success', description: '01712345678' },
      { id: '2', type: 'Add Balance', amount: 500, date: '2023-10-24 10:15', status: 'Success', description: 'Nagad Cash-in' },
    ];
    setHistory(mockHistory);
  }, []);

  const handleLogin = (phone: string) => {
    setUser({ id: 'u1', name: 'Mahid User', phone, balance: 1250.75 });
    setView('home');
  };

  const handleSignUp = (name: string, phone: string) => {
    setUser({ id: 'u2', name, phone, balance: 0 });
    setView('home');
  };

  const handleLogout = () => {
    setUser(null);
    setView('login');
  };

  const handleShare = () => {
    if (navigator.share) {
      navigator.share({
        title: APP_NAME,
        text: `Check out Mahid Telecom for easy recharge and bill pay!`,
        url: window.location.href,
      }).catch(console.error);
    } else {
      alert("Sharing not supported on this browser. Copy the URL instead.");
    }
  };

  const renderView = () => {
    if (!user && view !== 'signup') return <Login onLogin={handleLogin} onGoToSignUp={() => setView('signup')} />;
    if (!user && view === 'signup') return <SignUp onSignUp={handleSignUp} onGoToLogin={() => setView('login')} />;

    switch (view) {
      case 'home': return <HomeView user={user!} setView={setView} handleShare={handleShare} />;
      case 'recharge': return <MobileRecharge onBack={() => setView('home')} />;
      case 'add-balance': return <AddBalance onBack={() => setView('home')} />;
      case 'bill-pay': return <BillPay onBack={() => setView('home')} />;
      case 'transfer': return <BalanceTransfer onBack={() => setView('home')} />;
      case 'history': return (
        <div className="p-4">
          <h2 className="text-xl font-bold mb-4">Transaction History</h2>
          <div className="space-y-3">
            {history.map(tx => (
              <div key={tx.id} className="bg-white p-4 rounded-xl shadow-sm flex justify-between items-center">
                <div>
                  <p className="font-semibold text-gray-800">{tx.type}</p>
                  <p className="text-xs text-gray-500">{tx.date}</p>
                  <p className="text-sm text-gray-600">{tx.description}</p>
                </div>
                <div className="text-right">
                  <p className={`font-bold ${tx.type === 'Add Balance' ? 'text-green-600' : 'text-red-600'}`}>
                    {tx.type === 'Add Balance' ? '+' : '-'} ৳{tx.amount}
                  </p>
                  <span className="text-[10px] px-2 py-0.5 bg-green-100 text-green-700 rounded-full">{tx.status}</span>
                </div>
              </div>
            ))}
          </div>
        </div>
      );
      case 'profile': return (
        <div className="p-6">
          <div className="flex flex-col items-center mb-8">
            <div className="w-24 h-24 bg-blue-100 rounded-full flex items-center justify-center mb-4">
              <User size={48} className="text-blue-600" />
            </div>
            <h2 className="text-2xl font-bold">{user?.name}</h2>
            <p className="text-gray-500">{user?.phone}</p>
          </div>

          <div className="space-y-4">
            <button onClick={() => window.open(APK_DOWNLOAD_URL)} className="w-full flex items-center justify-between p-4 bg-white rounded-xl shadow-sm">
              <div className="flex items-center gap-3">
                <Download size={20} className="text-blue-600" />
                <span className="font-medium">Download APK</span>
              </div>
            </button>
            <button onClick={handleShare} className="w-full flex items-center justify-between p-4 bg-white rounded-xl shadow-sm">
              <div className="flex items-center gap-3">
                <Share2 size={20} className="text-indigo-600" />
                <span className="font-medium">Share App</span>
              </div>
            </button>
            <button onClick={() => window.open(WHATSAPP_LINK)} className="w-full flex items-center justify-between p-4 bg-white rounded-xl shadow-sm">
              <div className="flex items-center gap-3">
                <MessageSquare size={20} className="text-green-600" />
                <span className="font-medium">Contact WhatsApp</span>
              </div>
            </button>
            <button onClick={handleLogout} className="w-full flex items-center justify-between p-4 bg-red-50 text-red-600 rounded-xl">
              <div className="flex items-center gap-3">
                <LogOut size={20} />
                <span className="font-medium">Logout</span>
              </div>
            </button>
          </div>
        </div>
      );
      default: return <HomeView user={user!} setView={setView} handleShare={handleShare} />;
    }
  };

  return (
    <div className="max-w-md mx-auto bg-gray-50 min-h-screen relative pb-20 overflow-x-hidden shadow-2xl">
      {/* Header */}
      {user && view !== 'login' && view !== 'signup' && (
        <header className="bg-blue-700 text-white p-4 pt-6 rounded-b-3xl shadow-lg sticky top-0 z-50">
          <div className="flex justify-between items-center mb-2">
            <div className="flex items-center gap-2">
              <div className="bg-white/20 p-2 rounded-lg">
                <Smartphone size={20} />
              </div>
              <h1 className="text-lg font-bold tracking-tight">{APP_NAME}</h1>
            </div>
            <button onClick={() => setView('profile')} className="p-1 border-2 border-white/30 rounded-full">
              <User size={20} />
            </button>
          </div>
        </header>
      )}

      {/* Main Content */}
      <main className="animate-in fade-in duration-300">
        {renderView()}
      </main>

      {/* Bottom Navigation */}
      {user && view !== 'login' && view !== 'signup' && (
        <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-white border-t border-gray-100 flex justify-around p-3 safe-area-bottom shadow-[0_-4px_10px_rgba(0,0,0,0.05)] z-50">
          <button onClick={() => setView('home')} className={`flex flex-col items-center ${view === 'home' ? 'text-blue-600' : 'text-gray-400'}`}>
            <Home size={22} />
            <span className="text-[10px] mt-1 font-medium">Home</span>
          </button>
          <button onClick={() => setView('history')} className={`flex flex-col items-center ${view === 'history' ? 'text-blue-600' : 'text-gray-400'}`}>
            <History size={22} />
            <span className="text-[10px] mt-1 font-medium">History</span>
          </button>
          <button onClick={() => setView('profile')} className={`flex flex-col items-center ${view === 'profile' ? 'text-blue-600' : 'text-gray-400'}`}>
            <User size={22} />
            <span className="text-[10px] mt-1 font-medium">Profile</span>
          </button>
        </nav>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { APP_NAME } from '../constants';
import { ShieldCheck, Smartphone } from 'lucide-react';

interface LoginProps {
  onLogin: (phone: string) => void;
  onGoToSignUp: () => void;
}

const Login: React.FC<LoginProps> = ({ onLogin, onGoToSignUp }) => {
  const [phone, setPhone] = useState('');
  const [pin, setPin] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length === 11) {
      onLogin(phone);
    } else {
      alert("Please enter a valid 11-digit phone number");
    }
  };

  return (
    <div className="min-h-screen flex flex-col justify-center px-6 bg-gradient-to-br from-blue-700 to-indigo-800 text-white">
      <div className="text-center mb-10">
        <div className="bg-white/10 w-20 h-20 rounded-3xl flex items-center justify-center mx-auto mb-4 shadow-xl backdrop-blur-md">
          <Smartphone size={40} className="text-white" />
        </div>
        <h1 className="text-3xl font-bold tracking-tight">{APP_NAME}</h1>
        <p className="text-blue-100/70 mt-2">Fast. Secure. Reliable.</p>
      </div>

      <div className="bg-white text-gray-900 rounded-3xl p-8 shadow-2xl">
        <h2 className="text-xl font-bold mb-6 text-center text-gray-800">Login to your account</h2>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Mobile Number</label>
            <input
              type="tel"
              value={phone}
              onChange={(e) => setPhone(e.target.value.replace(/\D/g, '').slice(0, 11))}
              placeholder="01XXXXXXXXX"
              className="w-full px-4 py-3 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500"
              required
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Pin</label>
            <input
              type="password"
              value={pin}
              onChange={(e) => setPin(e.target.value.replace(/\D/g, '').slice(0, 6))}
              placeholder="6 Digit PIN"
              className="w-full px-4 py-3 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500"
              required
            />
          </div>
          <button
            type="submit"
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 px-4 rounded-xl transition-colors shadow-lg mt-2"
          >
            Login
          </button>
        </form>

        <div className="mt-6 text-center space-y-4">
          <button onClick={onGoToSignUp} className="text-blue-600 font-semibold text-sm hover:underline">
            Don't have an account? Sign Up
          </button>
          <div className="pt-4 flex items-center justify-center gap-2 text-gray-400 text-xs uppercase tracking-widest border-t border-gray-100">
            <ShieldCheck size={14} />
            <span>Secure Access</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;

