              >
                Prepaid
              </button>
              <button
                type="button"
                onClick={() => setRechargeType('Postpaid')}
                className={`flex-1 py-3 rounded-xl border font-bold ${rechargeType === 'Postpaid' ? 'bg-blue-50 border-blue-200 text-blue-700' : 'bg-white border-gray-100 text-gray-400'}`}
              >
                Postpaid
