                  >
                    ৳{val}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>

        <button
          type="submit"
          className="w-full bg-blue-600 text-white font-bold py-4 rounded-2xl shadow-lg hover:bg-blue-700 active:scale-[0.98] transition-all"
        >
          Confirm Recharge
        </button>
      </form>
    </div>
  );
};

